document.addEventListener('DOMContentLoaded',()=>{const mobileMenuBtn=document.querySelector('.mobile-menu-btn');const navLinks=document.querySelector('.nav-links');if(mobileMenuBtn){mobileMenuBtn.addEventListener('click',()=>{navLinks.classList.toggle('active');const icon=mobileMenuBtn.querySelector('i');if(navLinks.classList.contains('active')){icon.classList.remove('fa-bars');icon.classList.add('fa-times');}else{icon.classList.remove('fa-times');icon.classList.add('fa-bars');}});}const chatGate=document.getElementById('chatGate');const chatWrapper=document.getElementById('chatWrapper');const enterChatBtn=document.getElementById('enterChatBtn');if(chatGate && enterChatBtn){enterChatBtn.addEventListener('click',()=>{enterChatBtn.innerHTML='<i class="fas fa-spinner fa-spin"></i> Verifying...';enterChatBtn.disabled=true;setTimeout(()=>{chatGate.style.display='none';chatWrapper.style.display='block';const header=document.querySelector('header');if(header)header.style.display='none';const main=document.querySelector('main');if(main){main.style.marginTop='0';main.style.height='100vh';}const container=document.querySelector('.chat-container');if(container){container.style.height='100vh';}},1000);});}const currentLocation=location.pathname.split('/').pop();const navItems=document.querySelectorAll('.nav-links a');navItems.forEach(item=>{const href=item.getAttribute('href');if(href===currentLocation ||(currentLocation==='' && href==='index.html')){item.style.color='var(--primary-color)';}});});function onTurnstileSuccess(token){const enterChatBtn=document.getElementById('enterChatBtn');if(enterChatBtn){enterChatBtn.disabled=false;enterChatBtn.textContent='Join Room #IndiaDostiChat';}}document.addEventListener('DOMContentLoaded',()=>{const visitorCountEls=document.querySelectorAll('#visitor-count');if(visitorCountEls.length > 0){fetch('https://api.counterapi.dev/v1/indiadostichat/visitors/up').then(response=> response.json()).then(data=>{visitorCountEls.forEach(el=>{el.innerText=data.count;});}).catch(error=>{console.error('Error fetching visitor count:',error);visitorCountEls.forEach(el=>{el.innerText='Unavailable';});});}});